                status = 'DISPATCH_FAILED';
                error = String(e).slice(0, 1000);
              }
              fs.writeFileSync(path.join(resultsDir, file.replace(/\\.json$/, '_result.json')), JSON.stringify({status, workflow_id, ref, inputs, error, dispatched_at: new Date().toISOString()}, null, 2));
